content:
{
  "sentences": [
    {
      "text": "你好，我想要一杯小杯拿鐵，可以嗎？",
      "pinyin": "Nǐ hǎo, wǒ xiǎng yào yī bēi xiǎo bēi nátiě, kěyǐ ma?",
      "pinyin_numeric": "ni3 hao3, wo3 xiang3 yao4 yi1 bei1 xiao3 bei1 na2tie3, ke3yi3 ma0?",
      "translation_en": "Hello, I would like a small latte, okay?",
      "translation_ko": "안녕하세요, 작은 라떼 한 잔을 원하는데 괜찮을까요?"
    },
    {
      "text": "麻煩你，可以給我一杯冰紅茶嗎？",
      "pinyin": "Máfan nǐ, kěyǐ gěi wǒ yī bēi bīng hóngchá ma?",
      "pinyin_numeric": "ma2fan ni3, ke3yi3 gei3 wo3 yi1 bei1 bing1 hong2cha2 ma0?",
      "translation_en": "Excuse me, could you give me an iced black tea?",
      "translation_ko": "실례합니다, 아이스 홍차 한 잔 주실 수 있나요?"
    },
    {
      "text": "不好意思，可以幫我換成中杯嗎？",
      "pinyin": "Bù hǎo yìsi, kěyǐ bāng wǒ huàn chéng zhōng bēi ma?",
      "pinyin_numeric": "bu4 hao3 yi4si0, ke3yi3 bang1 wo3 huan4 cheng2 zhong1 bei1 ma0?",
      "translation_en": "Excuse me, could you help me change it to a medium cup?",
      "translation_ko": "죄송합니다, 중간 컵으로 바꿔 주실 수 있나요?"
    },
    {
      "text": "店員，可以給我一個袋子嗎？",
      "pinyin": "Diànyuán, kěyǐ gěi wǒ yī ge dàizi ma?",
      "pinyin_numeric": "dian4yuan2, ke3yi3 gei3 wo3 yi1 ge4 dai4zi0 ma0?",
      "translation_en": "Shop assistant, could you give me a bag?",
      "translation_ko": "점원님, 봉투 하나 주실 수 있나요?"
    },
    {
      "text": "我想要一杯綠茶，半糖，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi lǜchá, bàn táng, kěyǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 lü4cha2, ban4 tang2, ke3yi3 ma0?",
      "translation_en": "I would like a green tea, half sugar, okay?",
      "translation_ko": "녹차 한 잔, 반 당으로 할게요, 괜찮을까요?"
    },
    {
      "text": "可以給我一根吸管嗎？謝謝。",
      "pinyin": "Kěyǐ gěi wǒ yī gēn xīguǎn ma? Xièxie.",
      "pinyin_numeric": "ke3yi3 gei3 wo3 yi1 gen1 xi1guan3 ma0? xie4xie0.",
      "translation_en": "Could you give me a straw? Thank you.",
      "translation_ko": "빨대 하나 주실 수 있나요? 감사합니다."
    },
    {
      "text": "不好意思，可以再說一次價錢嗎？",
      "pinyin": "Bù hǎo yìsi, kěyǐ zài shuō yī cì jiàqián ma?",
      "pinyin_numeric": "bu4 hao3 yi4si0, ke3yi3 zai4 shuo1 yi1 ci4 jia4qian2 ma0?",
      "translation_en": "Excuse me, could you say the price again?",
      "translation_ko": "죄송합니다, 가격을 한 번 더 말씀해 주실 수 있나요?"
    },
    {
      "text": "可以幫我加珍珠嗎？沒問題。",
      "pinyin": "Kěyǐ bāng wǒ jiā zhēnzhū ma? Méi wèntí.",
      "pinyin_numeric": "ke3yi3 bang1 wo3 jia1 zhen1zhu1 ma0? mei2 wen4ti2.",
      "translation_en": "Could you help me add pearls? No problem.",
      "translation_ko": "펄 추가해 주실 수 있나요? 문제없어요."
    },
    {
      "text": "我想要一杯豆漿，內用，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi dòujiāng, nèiyòng, kěyǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 dou4jiang1, nei4yong4, ke3yi3 ma0?",
      "translation_en": "I would like a cup of soy milk, for here, okay?",
      "translation_ko": "두유 한 잔, 매장에서 먹을게요, 괜찮을까요?"
    },
    {
      "text": "可以給我一個湯匙嗎？麻煩你。",
      "pinyin": "Kěyǐ gěi wǒ yī ge tāngchí ma? Máfan nǐ.",
      "pinyin_numeric": "ke3yi3 gei3 wo3 yi1 ge4 tang1chi2 ma0? ma2fan ni3.",
      "translation_en": "Could you give me a spoon? Please.",
      "translation_ko": "숟가락 하나 주실 수 있나요? 부탁드립니다."
    }
  ]
}
